// Extract and sanitise email fields for GLM classification
const rawFrom = $json.from;
const fromDisplay = typeof rawFrom === 'string' ? rawFrom : (rawFrom?.value?.[0]?.address || rawFrom?.email || rawFrom?.address || String(rawFrom || ''));
const subject = String($json.subject || '');
const body = String($json.textPlain || $json.textHtml || $json.snippet || '').substring(0, 800);
const date = $json.date || $json.internalDate || new Date().toISOString();
const messageId = $json.id || $json.messageId || '';

// Sanitise body — strip HTML and collapse whitespace
const sanitised = body
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .substring(0, 500)
  .trim();

const cbKey = messageId.substring(0, 20) || Date.now().toString(36);

// Build classification prompt
const systemPrompt = `You classify emails for OrchestraCode, a UK cybersecurity compliance SaaS platform that helps SMEs achieve Cyber Essentials, Def Stan 05-138, and other certifications.

Return ONLY a JSON object (no markdown, no code fences) with these fields:

- category: one of: Security Advisory, CE / IASME Update, Data Protection, Defence Update, Procurement, Industry, Newsletter, Event, Sales Lead, General
- priority: High (urgent/actionable), Medium (relevant not urgent), Low (informational)
- suggestedAgent: security-agent | marketing | sales-researcher | product-manager | none
- emoji: single emoji matching the category
- reasoning: one sentence explaining why

Classify based on actual content, not just sender domain. Examples:
- An event invitation from NCSC is an Event, not a Security Advisory
- A procurement tender is Procurement even from a .gov.uk address
- A vulnerability disclosure IS a Security Advisory regardless of sender
- IASME scheme changes are CE / IASME Update
- A company asking about pricing is a Sales Lead`;

const userPrompt = `From: ${fromDisplay}\nSubject: ${subject}\nBody preview: ${sanitised}`;

return [{ json: {
  from: fromDisplay,
  subject,
  date,
  preview: sanitised,
  messageId,
  cbKey,
  systemPrompt,
  userPrompt
} }];

// Parse GLM classification response (Anthropic format)
const email = $node['Extract Email Data'].json;
let classification;

try {
  const response = $json;
  const content = response.content?.[0]?.text || '';

  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    classification = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON in response: ' + content.substring(0, 100));
  }
} catch (e) {
  // Fallback if GLM fails
  classification = {
    category: 'General',
    priority: 'Low',
    suggestedAgent: 'none',
    emoji: '\u2709\uFE0F',
    reasoning: 'Classification failed: ' + e.message
  };
}

return [{ json: {
  emoji: classification.emoji || '\u2709\uFE0F',
  category: classification.category || 'General',
  suggestedAgent: classification.suggestedAgent || 'none',
  priority: classification.priority || 'Low',
  reasoning: classification.reasoning || '',
  from: email.from,
  subject: email.subject,
  date: email.date,
  preview: email.preview,
  messageId: email.messageId,
  cbKey: email.cbKey
} }];
